package com.themuffinman.app.vision.service;
import com.themuffinman.app.vision.model.VisionConversation; import org.springframework.stereotype.Service;
@Service public class VisionUpdateAvailabilityRuleExecutionAdapter implements VisionCapabilityExecutionAdapter { private final VisionBusinessAvailabilityMutationService service; public VisionUpdateAvailabilityRuleExecutionAdapter(VisionBusinessAvailabilityMutationService s){service=s;} public String capabilityId(){return "update_availability_rule";} public VisionExecutionResult execute(VisionConversation c){try{service.updateRule(c.getSlotData(),c.getOwner());return VisionExecutionResult.executedAction(capabilityId());}catch(RuntimeException e){return VisionExecutionResult.blocked("The availability rule could not be updated.");}} }
